node <<'NODE'
const fs=require('fs');
const readme=fs.readFileSync('README.md','utf8');
const canonical='~/.config/opencode/plugins/flow.js';
const legacy='~/.opencode/plugins/flow.js';
const migrationHeader='## Migration / Upgrade';
const hasCanonical=readme.includes(canonical);
const migrationStart=readme.indexOf(migrationHeader);
const afterMigration=migrationStart===-1?'' : readme.slice(migrationStart + migrationHeader.length);
const nextH2Idx=afterMigration.search(/^##\s+/m);
const migrationSection= migrationStart===-1 ? '' : (nextH2Idx===-1 ? afterMigration : afterMigration.slice(0,nextH2Idx));
const hasMigrationHeader=migrationStart!==-1;
const hasLegacyInMigration= migrationSection.includes(legacy);
const legacyMentions=[...readme.matchAll(/~\/\.opencode\/plugins\/flow\.js/g)].map(m=>m.index);
const allLegacyInsideMigration=legacyMentions.every(i=>migrationStart!==-1 && i>=migrationStart && i<=migrationStart + migrationSection.length + migrationHeader.length);
const ok=hasCanonical&&hasMigrationHeader&&hasLegacyInMigration&&allLegacyInsideMigration;
console.log(JSON.stringify({hasCanonical,hasMigrationHeader,hasLegacyInMigration,legacyMentionCount:legacyMentions.length,allLegacyInsideMigration}));
process.exit(ok?0:1);
